import base64
import gzip
import hashlib
import io
import json
import random
from datetime import datetime, timezone
from pathlib import Path

import pandas as pd
import streamlit as st


st.set_page_config(page_title="TES Leixa — Test táctil", page_icon="🚑", layout="wide")

VERSION = "Banco v8.00 · archivo único blindado"
USER_STORE_PATH = Path("user_store.json")

# Banco incrustado: no depende de carpeta data/ ni CSV externo.
BANK_B64 = """"""


def now_iso():
    return datetime.now(timezone.utc).isoformat()


def n(value):
    if pd.isna(value):
        return ""
    return str(value).strip()


def hp(password, salt):
    return hashlib.sha256((salt + password).encode("utf-8")).hexdigest()


def make_default_store():
    def make_user(uid, display_name, password, role, must_change):
        salt = hashlib.sha256((uid + password + "tes-v800").encode("utf-8")).hexdigest()[:16]
        return {
            "display_name": display_name,
            "salt": salt,
            "password_hash": hp(password, salt),
            "role": role,
            "active": True,
            "must_change_password": must_change,
            "created_at": now_iso(),
            "updated_at": now_iso(),
        }

    users = {
        "diego": make_user("diego", "Diego", "tes2026", "administrador", False),
        "anton": make_user("anton", "Anton", "1234", "usuario", True),
        "melisa": make_user("melisa", "Melisa", "1111", "usuario", True),
        "elvira": make_user("elvira", "Elvira", "2222", "usuario", True),
        "lucia": make_user("lucia", "Lucia", "3333", "usuario", True),
    }
    return {
        "schema_version": "8.00",
        "updated_at": now_iso(),
        "users": users,
        "progress": {
            uid: {
                "answered": [],
                "wrong_ids": [],
                "correct_ids": [],
                "settings": {
                    "daily_goal": 142,
                    "target_pct": 90,
                    "study_days_first_round": 12,
                    "study_days_second_round": 12,
                },
            }
            for uid in users
        },
    }


def ensure_store(store):
    base = make_default_store()
    store.setdefault("schema_version", "8.00")
    store.setdefault("updated_at", now_iso())
    store.setdefault("users", {})
    store.setdefault("progress", {})
    for uid, user in base["users"].items():
        store["users"].setdefault(uid, user)
    for uid in store["users"]:
        store["progress"].setdefault(uid, {})
        p = store["progress"][uid]
        p.setdefault("answered", [])
        p.setdefault("wrong_ids", [])
        p.setdefault("correct_ids", [])
        p.setdefault("settings", {
            "daily_goal": 142,
            "target_pct": 90,
            "study_days_first_round": 12,
            "study_days_second_round": 12,
        })
    return store


def load_store():
    if USER_STORE_PATH.exists():
        try:
            return ensure_store(json.loads(USER_STORE_PATH.read_text(encoding="utf-8"))), "Archivo local"
        except Exception as exc:
            return make_default_store(), f"Nuevo por error leyendo archivo: {exc}"
    store = make_default_store()
    save_store_to_file(store)
    return store, "Archivo local creado"


def save_store_to_file(store):
    try:
        store["updated_at"] = now_iso()
        USER_STORE_PATH.write_text(json.dumps(store, ensure_ascii=False, indent=2), encoding="utf-8")
        return True, "Guardado local OK en user_store.json"
    except Exception as exc:
        return False, f"No se pudo guardar localmente: {exc}"


@st.cache_data(show_spinner=False)
def load_bank():
    raw = base64.b64decode(BANK_B64)
    with gzip.GzipFile(fileobj=io.BytesIO(raw), mode="rb") as gz:
        df = pd.read_csv(gz, dtype=str, encoding="utf-8-sig").fillna("")
    df.columns = [str(c).strip() for c in df.columns]

    needed = [
        "id", "modulo", "tema", "subtema", "nivel_dificultad", "tipo_pregunta",
        "enunciado", "opcion_a", "opcion_b", "opcion_c", "opcion_d", "respuesta_correcta",
        "explicacion", "porque_no_a", "porque_no_b", "porque_no_c", "porque_no_d",
        "regla_oro", "error_tipico", "tip_examen", "minileccion", "mnemotecnia",
        "tabla_esquema", "conceptos_clave", "estado_app",
    ]
    for col in needed:
        if col not in df.columns:
            df[col] = ""
    if "cuadro_aprendizaje" not in df.columns:
        df["cuadro_aprendizaje"] = df["tabla_esquema"]
    df["respuesta_correcta"] = df["respuesta_correcta"].str.upper().str.strip()
    df = df[df["respuesta_correcta"].isin(["A", "B", "C", "D"])].copy()
    return df.reset_index(drop=True)


def authenticate(store, uid, password):
    uid = uid.strip().lower()
    user = store.get("users", {}).get(uid)
    if not user or not user.get("active", False):
        return None
    if hp(password, user["salt"]) == user["password_hash"]:
        return user
    return None


def progress(store, uid):
    ensure_store(store)
    return store["progress"][uid]


def opt(q, letter):
    return n(q.get({"A":"opcion_a","B":"opcion_b","C":"opcion_c","D":"opcion_d"}[letter], ""))


def why(q, letter):
    return n(q.get(f"porque_no_{letter.lower()}", ""))


def seen_ids(p):
    return {str(x.get("id", "")) for x in p.get("answered", [])}


def detect_table(q):
    blob = " ".join(n(q.get(k, "")) for k in ["enunciado", "tema", "subtema", "conceptos_clave", "tabla_esquema"]).lower()
    if "glasgow" in blob or "retira al dolor" in blob:
        return """### Baremo de Glasgow

| Puntos | Ocular | Verbal | Motora |
|---:|---|---|---|
| 6 | — | — | Obedece órdenes |
| 5 | — | Orientado | Localiza el dolor |
| 4 | Espontánea | Confuso | Retira al dolor |
| 3 | Al habla | Palabras inapropiadas | Flexión anormal |
| 2 | Al dolor | Sonidos incomprensibles | Extensión anormal |
| 1 | Ninguna | Ninguna | Ninguna |

**Regla:** O + V + M. Retira dolor = M4; localiza dolor = M5."""
    if "start" in blob or "triaje" in blob:
        return """### START / triaje

| Criterio | Prioridad |
|---|---|
| Camina | Verde inicial, reevaluable |
| No respira tras abrir vía aérea | Negro |
| Respira tras abrir vía aérea | Rojo |
| FR > 30/min | Rojo |
| Perfusión alterada | Rojo |
| No obedece órdenes | Rojo |
| Resto no ambulante estable | Amarillo |"""
    if "fefo" in blob or "fifo" in blob or "stock" in blob or "caduc" in blob:
        return """### Stock / FEFO / FIFO

| Caso | Regla |
|---|---|
| Caducidad manda | FEFO |
| Entrada manda | FIFO |
| Caducado/no apto | Retirar y registrar |
| Termolábil | Mantener cadena de frío |
| Ruptura de stock | Reposición o alternativa segura |"""
    return ""


def render_failure(q, selected, correct):
    selected_text = opt(q, selected)
    correct_text = opt(q, correct)

    st.markdown("## 🚨 Aprendizaje obligatorio del fallo")
    st.markdown(f"### Correcta: **{correct}. {correct_text}**")
    st.markdown(f"**Tu respuesta:** {selected}. {selected_text}")

    table = n(q.get("cuadro_aprendizaje", "")) or n(q.get("tabla_esquema", "")) or detect_table(q)
    if table:
        st.markdown("### Tabla / esquema")
        st.markdown(table)

    exp = n(q.get("explicacion", ""))
    st.markdown("### Explicación")
    if exp:
        st.markdown(exp)
    else:
        st.markdown(
            f"La respuesta correcta es **{correct_text}**. La clave es relacionar el dato del enunciado "
            f"con **{n(q.get('tema',''))} / {n(q.get('subtema',''))}**."
        )

    st.markdown("### Por qué tu respuesta no era correcta")
    selected_why = why(q, selected)
    if selected_why:
        st.markdown(selected_why)
    else:
        st.markdown(
            f"**{selected_text}** puede pertenecer al mismo tema, pero no responde al criterio exacto del caso. "
            f"En esta pregunta manda **{correct_text}**."
        )

    st.markdown("### Descarte de distractores")
    any_detail = False
    for L in ["A", "B", "C", "D"]:
        if L == correct:
            continue
        txt = why(q, L)
        if txt:
            any_detail = True
            st.write(f"- **{L}. {opt(q, L)}:** {txt}")
    if not any_detail:
        for L in ["A", "B", "C", "D"]:
            if L != correct:
                st.write(f"- **{L}. {opt(q, L)}:** distractor cercano, pero no encaja con el dato diferencial.")

    st.markdown("### Regla de oro")
    st.markdown(n(q.get("regla_oro", "")) or "Ubica primero el contexto del caso y después aplica el criterio técnico exacto.")

    st.markdown("### Error típico")
    st.markdown(n(q.get("error_tipico", "")) or "Elegir una opción del mismo tema sin comprobar si encaja con el caso.")

    st.markdown("### Tip de examen")
    st.markdown(n(q.get("tip_examen", "")) or "Subraya fase, prioridad, estructura, signo clínico, zona o criterio numérico.")

    st.markdown("### Mini-lección")
    st.markdown(n(q.get("minileccion", "")) or "Estudia este punto como: concepto → criterio → caso donde se aplica → trampa habitual.")

    mn = n(q.get("mnemotecnia", ""))
    if mn:
        st.markdown("### Mnemotecnia")
        st.markdown(mn)

    conceptos = n(q.get("conceptos_clave", ""))
    if conceptos:
        st.markdown("### Conceptos clave")
        st.markdown(conceptos)


def init():
    defaults = {
        "store": None,
        "store_mode": "",
        "logged": False,
        "uid": "",
        "display_name": "",
        "role": "",
        "order": [],
        "idx": 0,
        "answered": False,
        "selected": None,
        "current_qid": "",
        "last_filter": "",
        "last_save": "",
    }
    for k, v in defaults.items():
        st.session_state.setdefault(k, v)


def reset_order(df):
    st.session_state.order = list(range(len(df)))
    random.shuffle(st.session_state.order)
    st.session_state.idx = 0
    st.session_state.answered = False
    st.session_state.selected = None
    st.session_state.current_qid = ""


def choose_work_df(df, p, mode, module):
    work = df.copy()
    if module != "Todos":
        work = work[work["modulo"] == module]

    seen = seen_ids(p)
    wrong = set(p.get("wrong_ids", []))

    if mode == "Solo no respondidas":
        work = work[~work["id"].isin(seen)]
    elif mode == "Solo mis fallos":
        work = work[work["id"].isin(wrong)]
    elif mode == "Alta/filtro_10":
        work = work[work["nivel_dificultad"].str.lower().str.contains("alta|filtro_10", na=False)]
    elif mode == "Plan de hoy":
        w1 = work[work["id"].isin(wrong)]
        w2 = work[~work["id"].isin(seen)]
        w3 = work[work["nivel_dificultad"].str.lower().str.contains("alta|filtro_10", na=False)]
        work = pd.concat([w1, w2, w3]).drop_duplicates("id")

    return work.reset_index(drop=True)


def login_page():
    st.title("🚑 TES Leixa — Acceso")
    st.caption(VERSION)
    st.info(f"Guardado: {st.session_state.store_mode}")

    uid = st.text_input("Usuario")
    pw = st.text_input("Contraseña", type="password")
    if st.button("Entrar", use_container_width=True):
        user = authenticate(st.session_state.store, uid, pw)
        if user:
            uid_clean = uid.strip().lower()
            st.session_state.logged = True
            st.session_state.uid = uid_clean
            st.session_state.display_name = user.get("display_name", uid_clean)
            st.session_state.role = user.get("role", "usuario")
            user["last_login"] = now_iso()
            ok, msg = save_store_to_file(st.session_state.store)
            st.session_state.last_save = msg
            st.rerun()
        else:
            st.error("Usuario o contraseña incorrectos.")


def app_page():
    df = load_bank()
    store = st.session_state.store
    uid = st.session_state.uid
    p = progress(store, uid)

    st.title("🚑 TES Leixa — Test táctil")
    st.caption(VERSION)

    c1, c2, c3, c4 = st.columns(4)
    total = len(df)
    seen = len(seen_ids(p))
    c1.metric("Banco", total)
    c2.metric("Vistas", seen)
    c3.metric("No vistas", max(total - seen, 0))
    c4.metric("Fallos pendientes", len(p.get("wrong_ids", [])))

    with st.sidebar:
        st.write(f"Usuario: **{st.session_state.display_name}**")
        st.write(f"Rol: **{st.session_state.role}**")
        st.write(f"Guardado: **{st.session_state.store_mode}**")
        st.write(f"Último guardado: {st.session_state.last_save}")
        mode = st.radio("Modo", ["Plan de hoy", "Solo no respondidas", "Solo mis fallos", "Alta/filtro_10", "Libre"])
        modules = ["Todos"] + sorted([x for x in df["modulo"].unique() if str(x).strip()])
        module = st.selectbox("Módulo", modules)
        if st.button("Reiniciar bloque"):
            st.session_state.order = []
            st.rerun()
        if st.button("Cerrar sesión"):
            st.session_state.logged = False
            st.rerun()

    work = choose_work_df(df, p, mode, module)

    filter_key = f"{mode}|{module}|{len(work)}"
    if st.session_state.last_filter != filter_key:
        st.session_state.last_filter = filter_key
        reset_order(work)

    if work.empty:
        st.warning("No hay preguntas con esos filtros.")
        return

    if not st.session_state.order:
        reset_order(work)

    if st.session_state.idx >= len(st.session_state.order):
        st.success("Bloque terminado.")
        if st.button("Nuevo bloque"):
            reset_order(work)
            st.rerun()
        return

    q = work.iloc[st.session_state.order[st.session_state.idx]]
    qid = n(q.get("id"))
    correct = n(q.get("respuesta_correcta")).upper()

    st.divider()
    st.write(f"**Pregunta {st.session_state.idx + 1} de {len(st.session_state.order)}**")
    st.caption(f"{qid} · {n(q.get('modulo'))} · {n(q.get('tema'))} · {n(q.get('nivel_dificultad'))}")
    st.markdown(f"### {n(q.get('enunciado'))}")

    # Si ya se respondió, muestra resultado fijo de la misma pregunta.
    if st.session_state.answered and st.session_state.current_qid == qid:
        selected = st.session_state.selected
        if selected == correct:
            st.success("Correcto. Esta pregunta queda dominada y no entra en repaso de fallos.")
        else:
            st.error(f"Incorrecto. Correcta: {correct}. {opt(q, correct)}")
            st.warning("Esta pregunta queda en 'Solo mis fallos'.")
            render_failure(q, selected, correct)

        if st.button("Siguiente pregunta", use_container_width=True):
            st.session_state.idx += 1
            st.session_state.answered = False
            st.session_state.selected = None
            st.session_state.current_qid = ""
            st.rerun()
        return

    for L in ["A", "B", "C", "D"]:
        if st.button(f"{L}. {opt(q, L)}", key=f"{qid}_{L}", use_container_width=True):
            selected = L
            ok = selected == correct
            entry = {
                "timestamp": now_iso(),
                "id": qid,
                "modulo": n(q.get("modulo")),
                "tema": n(q.get("tema")),
                "subtema": n(q.get("subtema")),
                "dificultad": n(q.get("nivel_dificultad")),
                "respuesta_usuario": selected,
                "respuesta_correcta": correct,
                "correcta": int(ok),
            }
            p["answered"].append(entry)

            if ok:
                if qid not in p["correct_ids"]:
                    p["correct_ids"].append(qid)
                if qid in p["wrong_ids"]:
                    p["wrong_ids"].remove(qid)
            else:
                if qid not in p["wrong_ids"]:
                    p["wrong_ids"].append(qid)

            ok_save, msg = save_store_to_file(store)
            st.session_state.last_save = msg
            st.session_state.answered = True
            st.session_state.selected = selected
            st.session_state.current_qid = qid

            # Mostrar resultado y explicación INMEDIATAMENTE, sin esperar rerun.
            if ok:
                st.success("Correcto. Esta pregunta queda dominada y no entra en repaso de fallos.")
            else:
                st.error(f"Incorrecto. Correcta: {correct}. {opt(q, correct)}")
                st.warning("Esta pregunta queda en 'Solo mis fallos'.")
                render_failure(q, selected, correct)

            if st.button("Siguiente pregunta", key=f"next_after_{qid}", use_container_width=True):
                st.session_state.idx += 1
                st.session_state.answered = False
                st.session_state.selected = None
                st.session_state.current_qid = ""
                st.rerun()


init()
if st.session_state.store is None:
    st.session_state.store, st.session_state.store_mode = load_store()

if not st.session_state.logged:
    login_page()
else:
    app_page()
